  if (new_full_value > current_full_value) {
    dense_bucket_[register_index] = std::bitset<DENSE_BUCKET_SIZE>(dense_value);
    if (overflow_value > 0) {
      overflow_bucket_[register_index] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_value);
