  uint16_t m = 1;
  if (n_leading_bits_ > 0) {
    m = 1 << n_leading_bits_;  // 2^n_leading_bits
  }

  // Calculate sum of 2^(-register_value)
  double sum = 0.0;
  for (uint16_t i = 0; i < m; i++) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
