#include <iostream>
#include <string>

#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"

using namespace bustub;

int main() {
  // Test HyperLogLog with string
  {
    auto obj = HyperLogLog<std::string>(static_cast<int16_t>(1));
    std::cout << "Initial cardinality: " << obj.GetCardinality() << std::endl;

    obj.AddElem("Welcome to CMU DB (15-445/645)");
    obj.ComputeCardinality();
    std::cout << "After 1 element: " << obj.GetCardinality() << std::endl;

    obj.AddElem("Andy");
    obj.AddElem("Connor");
    obj.AddElem("J-How");
    obj.AddElem("Kunle");
    obj.AddElem("Lan");
    obj.AddElem("Prashanth");
    obj.AddElem("William");
    obj.AddElem("Yash");
    obj.AddElem("Yuanxin");

    obj.ComputeCardinality();
    std::cout << "After 10 unique strings: " << obj.GetCardinality() << std::endl;
  }

  // Test HyperLogLogPresto with int64
  {
    auto obj = HyperLogLogPresto<int64_t>(static_cast<int16_t>(1));
    std::cout << "\nPresto initial cardinality: " << obj.GetCardinality() << std::endl;

    obj.AddElem(262144);
    obj.ComputeCardinality();
    std::cout << "After adding 262144: " << obj.GetCardinality() << std::endl;

    auto dense = obj.GetDenseBucket();
    std::cout << "Dense[0]: " << dense[0].to_ullong() << ", expected: 2" << std::endl;
    std::cout << "Overflow[0]: " << obj.GetOverflowBucketofIndex(0).to_ullong() << ", expected: 1" << std::endl;

    obj.AddElem(0);
    obj.ComputeCardinality();
    std::cout << "After adding 0: " << obj.GetCardinality() << std::endl;

    dense = obj.GetDenseBucket();
    std::cout << "Dense[0]: " << dense[0].to_ullong() << ", expected: 15" << std::endl;
    std::cout << "Overflow[0]: " << obj.GetOverflowBucketofIndex(0).to_ullong() << ", expected: 3" << std::endl;
  }

  std::cout << "\nBasic tests completed!" << std::endl;
  return 0;
}

