#include "primer/hyperloglog.h"
#include "primer/hyperloglog_presto.h"

using namespace bustub;

int main() {
  // Test HyperLogLogPresto with int64 (doesn't use Value/Type system)
  {
    std::cout << "Testing HyperLogLogPresto<int64_t>" << std::endl;

    auto obj = HyperLogLogPresto<int64_t>(static_cast<int16_t>(1));
    std::cout << "Initial cardinality: " << obj.GetCardinality() << std::endl;

    std::cout << "Adding 262144..." << std::endl;
    obj.AddElem(262144);

    std::cout << "Computing cardinality..." << std::endl;
    obj.ComputeCardinality();
    std::cout << "Cardinality: " << obj.GetCardinality() << std::endl;

    auto dense = obj.GetDenseBucket();
    std::cout << "Dense[0]: " << dense[0].to_ullong() << " (expected: 2)" << std::endl;
    std::cout << "Overflow[0]: " << obj.GetOverflowBucketofIndex(0).to_ullong() << " (expected: 1)" << std::endl;

    std::cout << "Adding 0..." << std::endl;
    obj.AddElem(0);
    obj.ComputeCardinality();

    dense = obj.GetDenseBucket();
    std::cout << "Dense[0] after adding 0: " << dense[0].to_ullong() << " (expected: 15)" << std::endl;
    std::cout << "Overflow[0] after adding 0: " << obj.GetOverflowBucketofIndex(0).to_ullong() << " (expected: 3)" << std::endl;

    std::cout << "\nTest completed!" << std::endl;
  }

  return 0;
